1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	  <meta charset="UTF-8">
5	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	  <title>Content Cluster Map</title>
7	  <style>
8	    :root {
9	      --bg: #ffffff;
10	      --bg-secondary: #f8f9fa;
11	      --text: #1a1a2e;
12	      --text-secondary: #555555;
13	      --border: #e0e0e0;
14	      --pillar-fill: #1e3a5f;
15	      --pillar-stroke: #16304d;
16	      --link-mandatory: #4E79A7;
17	      --link-recommended: #76B7B2;
18	      --link-optional: #B07AA1;
19	      --tooltip-bg: #1a1a2e;
20	      --tooltip-text: #ffffff;
21	      --stats-bg: #f0f4f8;
22	      --written-opacity: 1.0;
23	      --planned-opacity: 0.6;
24	    }
25	
26	    @media (prefers-color-scheme: dark) {
27	      :root {
28	        --bg: #1a1a2e;
29	        --bg-secondary: #16213e;
30	        --text: #e0e0e0;
31	        --text-secondary: #aaaaaa;
32	        --border: #333355;
33	        --pillar-fill: #2d5a8f;
34	        --pillar-stroke: #4E79A7;
35	        --tooltip-bg: #0f0f23;
36	        --tooltip-text: #e0e0e0;
37	        --stats-bg: #16213e;
38	      }
39	    }
40	
41	    * {
42	      margin: 0;
43	      padding: 0;
44	      box-sizing: border-box;
45	    }
46	
47	    body {
48	      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
49	      background: var(--bg);
50	      color: var(--text);
51	      min-height: 100vh;
52	      display: flex;
53	      flex-direction: column;
54	    }
55	
56	    header {
57	      text-align: center;
58	      padding: 24px 16px 8px;
59	    }
60	
61	    header h1 {
62	      font-size: 1.5rem;
63	      font-weight: 700;
64	      color: var(--text);
65	      margin-bottom: 4px;
66	    }
67	
68	    header p {
69	      font-size: 0.875rem;
70	      color: var(--text-secondary);
71	    }
72	
73	    .stats-bar {
74	      display: flex;
75	      justify-content: center;
76	      gap: 32px;
77	      padding: 12px 16px;
78	      background: var(--stats-bg);
79	      border-top: 1px solid var(--border);
80	      border-bottom: 1px solid var(--border);
81	      flex-wrap: wrap;
82	    }
83	
84	    .stat {
85	      text-align: center;
86	    }
87	
88	    .stat-value {
89	      font-size: 1.25rem;
90	      font-weight: 700;
91	      color: var(--text);
92	    }
93	
94	    .stat-label {
95	      font-size: 0.75rem;
96	      color: var(--text-secondary);
97	      text-transform: uppercase;
98	      letter-spacing: 0.05em;
99	    }
100	
101	    .map-container {
102	      flex: 1;
103	      display: flex;
104	      align-items: center;
105	      justify-content: center;
106	      padding: 16px;
107	      min-height: 500px;
108	    }
109	
110	    svg {
111	      max-width: 100%;
112	      max-height: 80vh;
113	    }
114	
115	    .pillar-node {
116	      cursor: pointer;
117	      transition: transform 0.2s ease;
118	    }
119	
120	    .pillar-node:hover {
121	      filter: brightness(1.1);
122	    }
123	
124	    .spoke-node {
125	      cursor: pointer;
126	      transition: opacity 0.2s ease;
127	    }
128	
129	    .spoke-node:hover {
130	      filter: brightness(1.15);
131	    }
132	
133	    .spoke-node.planned {
134	      opacity: var(--planned-opacity);
135	      stroke-dasharray: 4 2;
136	    }
137	
138	    .spoke-node.written {
139	      opacity: var(--written-opacity);
140	    }
141	
142	    .link-line {
143	      transition: opacity 0.2s ease, stroke-width 0.2s ease;
144	    }
145	
146	    .link-line.mandatory {
147	      stroke: var(--link-mandatory);
148	      stroke-width: 2;
149	    }
150	
151	    .link-line.recommended {
152	      stroke: var(--link-recommended);
153	      stroke-width: 1.5;
154	      stroke-dasharray: 6 3;
155	    }
156	
157	    .link-line.optional {
158	      stroke: var(--link-optional);
159	      stroke-width: 1;
160	      stroke-dasharray: 3 3;
161	    }
162	
163	    .link-line.dimmed {
164	      opacity: 0.1;
165	    }
166	
167	    .link-line.highlighted {
168	      opacity: 1;
169	      stroke-width: 3;
170	    }
171	
172	    .node-label {
173	      font-size: 11px;
174	      fill: var(--text);
175	      text-anchor: middle;
176	      pointer-events: none;
177	      user-select: none;
178	    }
179	
180	    .pillar-label {
181	      font-size: 13px;
182	      font-weight: 700;
183	      fill: #ffffff;
184	      text-anchor: middle;
185	      pointer-events: none;
186	      user-select: none;
187	    }
188	
189	    .cluster-label {
190	      font-size: 10px;
191	      fill: var(--text-secondary);
192	      text-anchor: middle;
193	      pointer-events: none;
194	      font-style: italic;
195	    }
196	
197	    .tooltip {
198	      position: fixed;
199	      background: var(--tooltip-bg);
200	      color: var(--tooltip-text);
201	      padding: 12px 16px;
202	      border-radius: 8px;
203	      font-size: 0.8125rem;
204	      line-height: 1.5;
205	      max-width: 280px;
206	      pointer-events: none;
207	      opacity: 0;
208	      transition: opacity 0.15s ease;
209	      z-index: 100;
210	      box-shadow: 0 4px 16px rgba(0, 0, 0, 0.3);
211	    }
212	
213	    .tooltip.visible {
214	      opacity: 1;
215	    }
216	
217	    .tooltip-title {
218	      font-weight: 700;
219	      margin-bottom: 4px;
220	    }
221	
222	    .tooltip-detail {
223	      display: flex;
224	      justify-content: space-between;
225	      gap: 16px;
226	    }
227	
228	    .tooltip-detail span:first-child {
229	      color: var(--text-secondary);
230	    }
231	
232	    .legend {
233	      display: flex;
234	      justify-content: center;
235	      gap: 24px;
236	      padding: 8px 16px;
237	      flex-wrap: wrap;
238	    }
239	
240	    .legend-item {
241	      display: flex;
242	      align-items: center;
243	      gap: 6px;
244	      font-size: 0.75rem;
245	      color: var(--text-secondary);
246	    }
247	
248	    .legend-line {
249	      width: 24px;
250	      height: 2px;
251	    }
252	
253	    .legend-line.mandatory { background: var(--link-mandatory); }
254	    .legend-line.recommended { background: var(--link-recommended); background-image: repeating-linear-gradient(90deg, var(--link-recommended) 0 6px, transparent 6px 9px); background-color: transparent; height: 2px;}
255	    .legend-line.optional { background: var(--link-optional); background-image: repeating-linear-gradient(90deg, var(--link-optional) 0 3px, transparent 3px 6px); background-color: transparent; height: 1px;}
256	
257	    .legend-dot {
258	      width: 10px;
259	      height: 10px;
260	      border-radius: 50%;
261	    }
262	
263	    .legend-dot.written { background: #59A14F; }
264	    .legend-dot.planned { background: #59A14F; opacity: 0.5; border: 1px dashed #59A14F; }
265	
266	    footer {
267	      text-align: center;
268	      padding: 12px 16px;
269	      font-size: 0.75rem;
270	      color: var(--text-secondary);
271	      border-top: 1px solid var(--border);
272	    }
273	  </style>
274	</head>
275	<body>
276	  <header>
277	    <h1 id="map-title">Content Cluster Map</h1>
278	    <p id="map-subtitle">SERP-based semantic topic clustering</p>
279	  </header>
280	
281	  <div class="stats-bar">
282	    <div class="stat">
283	      <div class="stat-value" id="stat-posts">0</div>
284	      <div class="stat-label">Total Posts</div>
285	    </div>
286	    <div class="stat">
287	      <div class="stat-value" id="stat-clusters">0</div>
288	      <div class="stat-label">Clusters</div>
289	    </div>
290	    <div class="stat">
291	      <div class="stat-value" id="stat-links">0</div>
292	      <div class="stat-label">Internal Links</div>
293	    </div>
294	    <div class="stat">
295	      <div class="stat-value" id="stat-words">0</div>
296	      <div class="stat-label">Est. Words</div>
297	    </div>
298	  </div>
299	
300	  <div class="map-container">
301	    <svg id="cluster-svg" role="img" aria-label="Content cluster visualization showing pillar page connected to topic clusters and spoke pages">
302	      <title>Content Cluster Map</title>
303	      <desc>Interactive visualization of a hub-and-spoke content architecture. The central pillar node connects to surrounding cluster groups, each containing spoke pages.</desc>
304	    </svg>
305	  </div>
306	
307	  <div class="legend">
308	    <div class="legend-item"><div class="legend-line mandatory"></div> Mandatory link</div>
309	    <div class="legend-item"><div class="legend-line recommended"></div> Recommended link</div>
310	    <div class="legend-item"><div class="legend-line optional"></div> Optional link</div>
311	    <div class="legend-item"><div class="legend-dot written"></div> Written</div>
312	    <div class="legend-item"><div class="legend-dot planned"></div> Planned</div>
313	  </div>
314	
315	  <footer>Generated by Claude SEO v1.9.0</footer>
316	
317	  <div class="tooltip" id="tooltip"></div>
318	
319	  <script>
320	    // === CLUSTER DATA (replaced by skill at generation time) ===
321	    const CLUSTER_DATA = {
322	      pillar: { title: "Sample Pillar Page", keyword: "sample keyword", volume: 5000, template: "ultimate-guide", wordCount: 3500, url: "/pillar" },
323	      clusters: [
324	        {
325	          name: "Sample Cluster",
326	          color: "#4E79A7",
327	          posts: [
328	            { title: "Sample Post 1", keyword: "sample post 1", volume: 1200, template: "how-to", wordCount: 1500, url: "/post-1", status: "planned" },
329	            { title: "Sample Post 2", keyword: "sample post 2", volume: 800, template: "listicle", wordCount: 1400, url: "/post-2", status: "planned" }
330	          ]
331	        }
332	      ],
333	      links: [
334	        { from: "pillar", to: "cluster-0-post-0", type: "mandatory" },
335	        { from: "cluster-0-post-0", to: "pillar", type: "mandatory" }
336	      ],
337	      meta: { totalPosts: 3, totalClusters: 1, totalLinks: 2, estimatedWords: 6400 }
338	    };
339	    // === END CLUSTER DATA ===
340	
341	    const COLORS = ["#4E79A7", "#F28E2B", "#E15759", "#76B7B2", "#59A14F", "#EDC948", "#B07AA1", "#FF9DA7"];
342	
343	    (function render() {
344	      const data = CLUSTER_DATA;
345	      const svg = document.getElementById("cluster-svg");
346	      const tooltip = document.getElementById("tooltip");
347	
348	      // Update header
349	      document.getElementById("map-title").textContent = data.pillar.title || "Content Cluster Map";
350	      document.getElementById("map-subtitle").textContent = "Cluster map for: " + data.pillar.keyword;
351	
352	      // Update stats
353	      document.getElementById("stat-posts").textContent = data.meta.totalPosts;
354	      document.getElementById("stat-clusters").textContent = data.meta.totalClusters;
355	      document.getElementById("stat-links").textContent = data.meta.totalLinks;
356	      document.getElementById("stat-words").textContent = data.meta.estimatedWords.toLocaleString();
357	
358	      // Layout calculations
359	      const numClusters = data.clusters.length;
360	      const maxPostsInCluster = Math.max(...data.clusters.map(c => c.posts.length), 1);
361	      const baseRadius = 140;
362	      const clusterRadius = baseRadius + numClusters * 15;
363	      const spokeRadius = 55 + maxPostsInCluster * 10;
364	      const totalRadius = clusterRadius + spokeRadius + 60;
365	      const cx = totalRadius + 40;
366	      const cy = totalRadius + 40;
367	      const width = (totalRadius + 40) * 2;
368	      const height = (totalRadius + 40) * 2;
369	
370	      svg.setAttribute("viewBox", "0 0 " + width + " " + height);
371	      svg.setAttribute("width", Math.min(width, 900));
372	      svg.setAttribute("height", Math.min(height, 900));
373	
374	      // Build node position map
375	      const nodePositions = {};
376	      nodePositions["pillar"] = { x: cx, y: cy };
377	
378	      const clusterCenters = [];
379	      for (let ci = 0; ci < numClusters; ci++) {
380	        const angle = (2 * Math.PI * ci) / numClusters - Math.PI / 2;
381	        const ccx = cx + Math.cos(angle) * clusterRadius;
382	        const ccy = cy + Math.sin(angle) * clusterRadius;
383	        clusterCenters.push({ x: ccx, y: ccy, angle: angle });
384	
385	        const cluster = data.clusters[ci];
386	        const numPosts = cluster.posts.length;
387	        for (let pi = 0; pi < numPosts; pi++) {
388	          const spreadAngle = Math.PI * 0.6;
389	          const startAngle = angle - spreadAngle / 2;
390	          const postAngle = numPosts === 1
391	            ? angle
392	            : startAngle + (spreadAngle * pi) / (numPosts - 1);
393	          const px = ccx + Math.cos(postAngle) * spokeRadius;
394	          const py = ccy + Math.sin(postAngle) * spokeRadius;
395	          const nodeId = "cluster-" + ci + "-post-" + pi;
396	          nodePositions[nodeId] = { x: px, y: py };
397	        }
398	      }
399	
400	      // SVG content assembly
401	      let svgContent = "";
402	
403	      // Draw links first (behind nodes)
404	      const linkElements = [];
405	      data.links.forEach(function(link, idx) {
406	        const fromPos = nodePositions[link.from];
407	        const toPos = nodePositions[link.to];
408	        if (!fromPos || !toPos) return;
409	        const linkClass = "link-line " + link.type;
410	        const linkId = "link-" + idx;
411	        svgContent += '<line id="' + linkId + '" class="' + linkClass + '" '
412	          + 'x1="' + fromPos.x + '" y1="' + fromPos.y + '" '
413	          + 'x2="' + toPos.x + '" y2="' + toPos.y + '" '
414	          + 'data-from="' + link.from + '" data-to="' + link.to + '"/>';
415	        linkElements.push(linkId);
416	      });
417	
418	      // Draw cluster group labels
419	      clusterCenters.forEach(function(cc, ci) {
420	        const cluster = data.clusters[ci];
421	        const labelAngle = cc.angle;
422	        const labelDist = clusterRadius * 0.55;
423	        const lx = cx + Math.cos(labelAngle) * labelDist;
424	        const ly = cy + Math.sin(labelAngle) * labelDist;
425	        svgContent += '<text class="cluster-label" x="' + lx + '" y="' + ly + '">'
426	          + escapeHtml(cluster.name) + '</text>';
427	      });
428	
429	      // Draw spoke nodes
430	      data.clusters.forEach(function(cluster, ci) {
431	        const color = cluster.color || COLORS[ci % COLORS.length];
432	        cluster.posts.forEach(function(post, pi) {
433	          const nodeId = "cluster-" + ci + "-post-" + pi;
434	          const pos = nodePositions[nodeId];
435	          const statusClass = post.status === "written" ? "written" : "planned";
436	          svgContent += '<g class="spoke-node ' + statusClass + '" data-node="' + nodeId + '">'
437	            + '<circle cx="' + pos.x + '" cy="' + pos.y + '" r="22" '
438	            + 'fill="' + color + '" stroke="' + darken(color) + '" stroke-width="2"/>'
439	            + '<text class="node-label" x="' + pos.x + '" y="' + (pos.y + 34) + '">'
440	            + escapeHtml(truncate(post.title, 18))
441	            + '</text></g>';
442	        });
443	      });
444	
445	      // Draw pillar node (on top)
446	      svgContent += '<g class="pillar-node" data-node="pillar">'
447	        + '<circle cx="' + cx + '" cy="' + cy + '" r="38" '
448	        + 'fill="' + getComputedStyle(document.documentElement).getPropertyValue("--pillar-fill").trim() + '" '
449	        + 'stroke="' + getComputedStyle(document.documentElement).getPropertyValue("--pillar-stroke").trim() + '" '
450	        + 'stroke-width="3"/>'
451	        + '<text class="pillar-label" x="' + cx + '" y="' + (cy - 4) + '">'
452	        + escapeHtml(truncate(data.pillar.title, 16))
453	        + '</text>'
454	        + '<text class="pillar-label" x="' + cx + '" y="' + (cy + 12) + '" style="font-size:9px;font-weight:400;opacity:0.8">'
455	        + 'PILLAR'
456	        + '</text></g>';
457	
458	      svg.innerHTML = svgContent;
459	
460	      // Tooltip handling
461	      function showTooltip(e, nodeId) {
462	        let info;
463	        if (nodeId === "pillar") {
464	          info = data.pillar;
465	        } else {
466	          const parts = nodeId.match(/cluster-(\d+)-post-(\d+)/);
467	          if (!parts) return;
468	          info = data.clusters[parseInt(parts[1])].posts[parseInt(parts[2])];
469	        }
470	        if (!info) return;
471	
472	        let html = '<div class="tooltip-title">' + escapeHtml(info.title) + '</div>';
473	        html += '<div class="tooltip-detail"><span>Keyword:</span><span>' + escapeHtml(info.keyword) + '</span></div>';
474	        html += '<div class="tooltip-detail"><span>Volume:</span><span>' + (info.volume || "N/A") + '</span></div>';
475	        html += '<div class="tooltip-detail"><span>Template:</span><span>' + escapeHtml(info.template) + '</span></div>';
476	        html += '<div class="tooltip-detail"><span>Words:</span><span>' + info.wordCount.toLocaleString() + '</span></div>';
477	        if (info.status) {
478	          html += '<div class="tooltip-detail"><span>Status:</span><span>' + info.status + '</span></div>';
479	        }
480	
481	        tooltip.innerHTML = html;
482	        tooltip.classList.add("visible");
483	
484	        const rect = tooltip.getBoundingClientRect();
485	        let tx = e.clientX + 12;
486	        let ty = e.clientY + 12;
487	        if (tx + rect.width > window.innerWidth) tx = e.clientX - rect.width - 12;
488	        if (ty + rect.height > window.innerHeight) ty = e.clientY - rect.height - 12;
489	        tooltip.style.left = tx + "px";
490	        tooltip.style.top = ty + "px";
491	      }
492	
493	      function hideTooltip() {
494	        tooltip.classList.remove("visible");
495	      }
496	
497	      function highlightLinks(nodeId) {
498	        document.querySelectorAll(".link-line").forEach(function(line) {
499	          if (line.dataset.from === nodeId || line.dataset.to === nodeId) {
500	            line.classList.add("highlighted");
501	            line.classList.remove("dimmed");
502	          } else {
503	            line.classList.add("dimmed");
504	            line.classList.remove("highlighted");
505	          }
506	        });
507	      }
508	
509	      function resetLinks() {
510	        document.querySelectorAll(".link-line").forEach(function(line) {
511	          line.classList.remove("highlighted", "dimmed");
512	        });
513	      }
514	
515	      // Attach event listeners to nodes
516	      document.querySelectorAll(".pillar-node, .spoke-node").forEach(function(node) {
517	        const nodeId = node.dataset.node;
518	
519	        node.addEventListener("mouseenter", function(e) {
520	          showTooltip(e, nodeId);
521	          highlightLinks(nodeId);
522	        });
523	
524	        node.addEventListener("mousemove", function(e) {
525	          const rect = tooltip.getBoundingClientRect();
526	          let tx = e.clientX + 12;
527	          let ty = e.clientY + 12;
528	          if (tx + rect.width > window.innerWidth) tx = e.clientX - rect.width - 12;
529	          if (ty + rect.height > window.innerHeight) ty = e.clientY - rect.height - 12;
530	          tooltip.style.left = tx + "px";
531	          tooltip.style.top = ty + "px";
532	        });
533	
534	        node.addEventListener("mouseleave", function() {
535	          hideTooltip();
536	          resetLinks();
537	        });
538	
539	        node.addEventListener("focus", function(e) {
540	          showTooltip(e, nodeId);
541	          highlightLinks(nodeId);
542	        });
543	
544	        node.addEventListener("blur", function() {
545	          hideTooltip();
546	          resetLinks();
547	        });
548	      });
549	
550	      // Keyboard accessibility
551	      document.querySelectorAll(".pillar-node, .spoke-node").forEach(function(node) {
552	        node.setAttribute("tabindex", "0");
553	        node.setAttribute("role", "button");
554	        const nodeId = node.dataset.node;
555	        let label;
556	        if (nodeId === "pillar") {
557	          label = "Pillar page: " + data.pillar.title;
558	        } else {
559	          const parts = nodeId.match(/cluster-(\d+)-post-(\d+)/);
560	          if (parts) {
561	            const post = data.clusters[parseInt(parts[1])].posts[parseInt(parts[2])];
562	            label = "Spoke page: " + post.title;
563	          }
564	        }
565	        if (label) node.setAttribute("aria-label", label);
566	      });
567	    })();
568	
569	    // Utility functions
570	    function escapeHtml(str) {
571	      var div = document.createElement("div");
572	      div.textContent = str;
573	      return div.innerHTML;
574	    }
575	
576	    function truncate(str, maxLen) {
577	      if (!str) return "";
578	      return str.length > maxLen ? str.substring(0, maxLen - 1) + "\u2026" : str;
579	    }
580	
581	    function darken(hex) {
582	      var r = parseInt(hex.slice(1, 3), 16);
583	      var g = parseInt(hex.slice(3, 5), 16);
584	      var b = parseInt(hex.slice(5, 7), 16);
585	      r = Math.max(0, Math.floor(r * 0.75));
586	      g = Math.max(0, Math.floor(g * 0.75));
587	      b = Math.max(0, Math.floor(b * 0.75));
588	      return "#" + ((1 << 24) + (r << 16) + (g << 8) + b).toString(16).slice(1);
589	    }
590	  </script>
591	</body>
592	</html>
